-- Разово удаляет демо-счета/платежи/контрагентов, засеянные первым запуском init.sql.
-- Целится по конкретным ID демо-записей — безопасно перезапускать, реальные данные не трогает.
DELETE FROM payments WHERE invoice_id IN (
  '10000000-0000-0000-0000-000000000001','10000000-0000-0000-0000-000000000002',
  '10000000-0000-0000-0000-000000000003','10000000-0000-0000-0000-000000000004',
  '10000000-0000-0000-0000-000000000005','10000000-0000-0000-0000-000000000006',
  '10000000-0000-0000-0000-000000000007'
);
DELETE FROM invoices WHERE id IN (
  '10000000-0000-0000-0000-000000000001','10000000-0000-0000-0000-000000000002',
  '10000000-0000-0000-0000-000000000003','10000000-0000-0000-0000-000000000004',
  '10000000-0000-0000-0000-000000000005','10000000-0000-0000-0000-000000000006',
  '10000000-0000-0000-0000-000000000007'
);
DELETE FROM counterparties WHERE id IN (
  '00000000-0000-0000-0000-000000000010','00000000-0000-0000-0000-000000000011',
  '00000000-0000-0000-0000-000000000012','00000000-0000-0000-0000-000000000013',
  '00000000-0000-0000-0000-000000000014'
);
